import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';

const API = 'http://localhost:8000';

export default function Dashboard() {
  const router = useRouter();
  const [folders, setFolders] = useState([]);
  const [guides, setGuides] = useState([]);
  const [newFolderName, setNewFolderName] = useState('');
  const [showNewFolder, setShowNewFolder] = useState(false);
  const [userEmail, setUserEmail] = useState('');

  function getToken() {
    return localStorage.getItem('authToken');
  }

  function headers() {
    return { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + getToken() };
  }

  useEffect(() => {
    if (!getToken()) { router.push('/'); return; }
    setUserEmail(localStorage.getItem('userEmail') || '');
    loadData();
  }, []);

  async function loadData() {
    try {
      const [foldersResp, guidesResp] = await Promise.all([
        fetch(API + '/folders', { headers: headers() }),
        fetch(API + '/guides', { headers: headers() })
      ]);
      const foldersData = await foldersResp.json();
      const guidesData = await guidesResp.json();
      setFolders(foldersData.folders || []);
      setGuides(guidesData.guides || []);
    } catch (e) {
      console.error('Failed to load data', e);
    }
  }

  async function createFolder() {
    if (!newFolderName.trim()) return;
    try {
      const resp = await fetch(API + '/folders', {
        method: 'POST',
        headers: headers(),
        body: JSON.stringify({ name: newFolderName.trim() })
      });
      const data = await resp.json();
      if (data.folder) {
        setFolders([data.folder, ...folders]);
        setNewFolderName('');
        setShowNewFolder(false);
      }
    } catch (e) {
      console.error('Failed to create folder', e);
    }
  }

  function logout() {
    localStorage.removeItem('authToken');
    localStorage.removeItem('userEmail');
    router.push('/');
  }

  function formatDate(dateStr) {
    const d = new Date(dateStr);
    return d.toLocaleDateString() + ' ' + d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }

  // Get guide count per folder
  function guideCount(folderId) {
    return guides.filter(g => g.folder_id === folderId).length;
  }

  // Guides not in any folder
  const unfolderedGuides = guides.filter(g => !g.folder_id);

  return (
    <div>
      <div className="navbar">
        <h1>AutoStudyAI</h1>
        <div>
          <span style={{ marginRight: 12, fontSize: '0.9em' }}>{userEmail}</span>
          <button onClick={logout}>Logout</button>
        </div>
      </div>

      <div className="container">
        {/* Folders Section */}
        <div className="section-header" style={{ marginTop: 20 }}>
          <h2>My Classes</h2>
        </div>

        <div className="folder-grid">
          {folders.map(folder => (
            <div key={folder.id} className="folder-card" onClick={() => router.push('/folder/' + folder.id)}>
              <h3>{folder.name}</h3>
              <p>{guideCount(folder.id)} study guides</p>
            </div>
          ))}
          <div className="folder-card add-folder-card" onClick={() => setShowNewFolder(true)}>
            {showNewFolder ? (
              <div onClick={e => e.stopPropagation()}>
                <input
                  type="text"
                  placeholder="Class name..."
                  value={newFolderName}
                  onChange={e => setNewFolderName(e.target.value)}
                  onKeyDown={e => { if (e.key === 'Enter') createFolder(); }}
                  style={{ marginBottom: 8, fontSize: '0.9em' }}
                  autoFocus
                />
                <div style={{ display: 'flex', gap: 6 }}>
                  <button className="btn btn-green" style={{ flex: 1, fontSize: '0.85em', padding: '6px 0' }} onClick={createFolder}>Create</button>
                  <button className="btn btn-gray" style={{ flex: 1, fontSize: '0.85em', padding: '6px 0' }} onClick={() => setShowNewFolder(false)}>Cancel</button>
                </div>
              </div>
            ) : (
              <div>
                <div style={{ fontSize: '2em' }}>+</div>
                <div>New Class</div>
              </div>
            )}
          </div>
        </div>

        {/* Recent Guides */}
        <div className="section-header" style={{ marginTop: 30 }}>
          <h2>Recent Study Guides</h2>
        </div>

        {guides.length === 0 ? (
          <div className="empty-state">
            No study guides yet. Use the Chrome extension to capture content!
          </div>
        ) : (
          guides.slice(0, 10).map(guide => (
            <div key={guide.id} className="card" onClick={() => router.push('/guide/' + guide.id)}>
              <h3>{guide.title}</h3>
              <p>
                {folders.find(f => f.id === guide.folder_id)?.name || 'No folder'}
                {' | '}
                <span className="timestamp">{formatDate(guide.created_at)}</span>
              </p>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
